example.code:
apiVersion: templates.gatekeeper.sh/v1 kind: ConstraintTemplate metadata: name: k8srequiredresources spec: crd: spec: names: kind: K8sRequiredResources targets: - target: admission.k8s.gatekeeper.sh rego: | package k8srequiredresources
violation[{"msg": msg}] { container := input.review.object.spec.containers[_] not container.resources.limits.cpu msg := sprintf("Container %v must have CPU limits", [container.name]) }
violation[{"msg": msg}] { container := input.review.object.spec.containers[_] not container.resources.limits.memory msg := sprintf("Container %v must have memory limits", [container.name]) }

apiVersion: templates.gatekeeper.sh/v1 kind: ConstraintTemplate metadata: name: k8sdenypriv spec: crd: spec: names: kind: K8sDenyPrivileged targets: - target: admission.k8s.gatekeeper.sh rego: | package k8sdenypriv
violation[{"msg": msg}] { container := input.review.object.spec.containers[_] container.securityContext.privileged == true msg := sprintf("Privileged containers not allowed: %v", [container.name]) }
violation[{"msg": msg}] { container := input.review.object.spec.initContainers[_] container.securityContext.privileged == true msg := sprintf("Privileged init containers not allowed: %v", [container.name]) }

apiVersion: templates.gatekeeper.sh/v1 kind: ConstraintTemplate metadata: name: k8strustedregistry spec: crd: spec: names: kind: K8sTrustedRegistry validation: openAPIV3Schema: type: object properties: registries: type: array items: type: string targets: - target: admission.k8s.gatekeeper.sh rego: | package k8strustedregistry
violation[{"msg": msg}] { container := input.review.object.spec.containers[_] not trusted_registry(container.image) msg := sprintf("Image %v is not from a trusted registry", [container.image]) }
trusted_registry(image) { registry := input.parameters.registries[_] startswith(image, registry) }

# terraform/policies/security.rego
package terraform.security

# Deny public S3 buckets
deny[msg] {
  resource := input.resource_changes[_]
  resource.type == "aws_s3_bucket"
  resource.change.after.acl == "public-read"
  msg := sprintf("S3 bucket %v cannot be public", [resource.address])
}

# Require encryption for RDS
deny[msg] {
  resource := input.resource_changes[_]
  resource.type == "aws_db_instance"
  not resource.change.after.storage_encrypted
  msg := sprintf("RDS instance %v must have encryption enabled", [resource.address])
}

# Require tagging
deny[msg] {
  resource := input.resource_changes[_]
  manageable_resource(resource.type)
  not resource.change.after.tags.Environment
  msg := sprintf("Resource %v must have Environment tag", [resource.address])
}

manageable_resource(type) {
  types := {"aws_instance", "aws_s3_bucket", "aws_rds_cluster", "aws_lambda_function"}
  types[type]
}

# templates/k8s-required-labels.yaml apiVersion: templates.gatekeeper.sh/v1 kind: ConstraintTemplate metadata: name: k8srequiredlabels annotations: description: "Requires specified labels on resources" spec: crd: spec: names: kind: K8sRequiredLabels validation: openAPIV3Schema: type: object properties: labels: type: array items: type: string targets: - target: admission.k8s.gatekeeper.sh rego: | package k8srequiredlabels
violation[{"msg": msg, "details": {"missing_labels": missing}}] { provided := {label | input.review.object.metadata.labels[label]} required := {label | label := input.parameters.labels[_]} missing := required - provided count(missing) > 0 msg := sprintf("Missing required labels: %v", [missing]) } --- # templates/k8s-container-limits.yaml apiVersion: templates.gatekeeper.sh/v1 kind: ConstraintTemplate metadata: name: k8scontainerlimits annotations: description: "Requires resource limits on containers" spec: crd: spec: names: kind: K8sContainerLimits validation: openAPIV3Schema: type: object properties: cpu: type: string memory: type: string targets: - target: admission.k8s.gatekeeper.sh rego: | package k8scontainerlimits
violation[{"msg": msg}] { container := input.review.object.spec.containers[_] not container.resources.limits.cpu msg := sprintf("Container %v has no CPU limit", [container.name]) }
violation[{"msg": msg}] { container := input.review.object.spec.containers[_] not container.resources.limits.memory msg := sprintf("Container %v has no memory limit", [container.name]) } --- # templates/k8s-deny-privileged.yaml apiVersion: templates.gatekeeper.sh/v1 kind: ConstraintTemplate metadata: name: k8sdenyprivileged annotations: description: "Denies privileged containers" spec: crd: spec: names: kind: K8sDenyPrivileged targets: - target: admission.k8s.gatekeeper.sh rego: | package k8sdenyprivileged
violation[{"msg": msg}] { c := input_containers[_] c.securityContext.privileged == true msg := sprintf("Privileged container not allowed: %v", [c.name]) }
input_containers[c] { c := input.review.object.spec.containers[_] }
input_containers[c] { c := input.review.object.spec.initContainers[_] }

# policies/terraform/main.rego
package terraform

import future.keywords.in

# Deny resources without required tags
deny[msg] {
  resource := input.resource_changes[_]
  taggable_resource(resource.type)
  not has_required_tags(resource)
  msg := sprintf("%s '%s' missing required tags", [resource.type, resource.address])
}

taggable_resource(type) {
  taggable_types := {
    "aws_instance",
    "aws_s3_bucket",
    "aws_rds_cluster",
    "aws_lambda_function",
    "aws_ecs_service"
  }
  type in taggable_types
}

has_required_tags(resource) {
  tags := resource.change.after.tags
  required := {"Environment", "Team", "Owner"}
  provided := {t | tags[t]}
  count(required - provided) == 0
}

# Deny public S3 buckets
deny[msg] {
  resource := input.resource_changes[_]
  resource.type == "aws_s3_bucket"
  resource.change.after.acl in {"public-read", "public-read-write"}
  msg := sprintf("S3 bucket '%s' cannot be public", [resource.address])
}

# Require encryption
deny[msg] {
  resource := input.resource_changes[_]
  resource.type == "aws_s3_bucket"
  not resource.change.after.server_side_encryption_configuration
  msg := sprintf("S3 bucket '%s' must have encryption", [resource.address])
}

# Deny unencrypted RDS
deny[msg] {
  resource := input.resource_changes[_]
  resource.type == "aws_db_instance"
  not resource.change.after.storage_encrypted
  msg := sprintf("RDS '%s' must have encryption enabled", [resource.address])
}
